use regex::Regex;

fn parse_player(input: &str) -> Result<(String, i32), Box<dyn std::error::Error>> {
  let re = Regex::new(r"(\w+): ([0-9]+)")?;
  if let Some(caps) = re.captures(input) {
    let player_name = caps[1].to_string();
    let score: i32 = caps[2].parse()?;
    Ok((player_name, score))
  } else {
    Err("Regex did not match".into())
  }
}
